insert into public.itineraries (
  slug_fr, slug_en, title_fr, title_en,
  meta_title_fr, meta_title_en, meta_desc_fr, meta_desc_en,
  intro_fr, intro_en,
  aeo_question_fr, aeo_answer_fr, aeo_question_en, aeo_answer_en,
  country_code, destination_region, destination_city, themes,
  duration_min_days, duration_max_days, travel_style, season,
  hotel_ids, sections, faq_content,
  related_ranking_ids, related_guide_slugs, related_itinerary_slugs,
  last_updated, status, priority, word_count_target
) values (
  'saint-tropez-ete-5-jours',
  'saint-tropez-summer-5-days',
  'Itinéraire Saint-Tropez 5 jours — luxe',
  'Saint-Tropez 5-day luxe itinerary',
  'Itinéraire Saint-Tropez été 5 jours luxe — Pampelonne, citadelle, Ramatuelle | MyConciergeHotel',
  'Itinerary Saint-Tropez 5 days | MyConciergeHotel',
  '5 jours à Saint-Tropez : Cheval Blanc, Lily of the Valley, Château de la Messardière. Pampelonne, citadelle, port, Ramatuelle. Sélection Concierge été luxe.',
  'A 5-day luxe itinerary in Saint-Tropez. Concierge timings, luxury hotels, luxe, mer highlights, and verified bookable addresses curated for MyConciergeHotel.',
  'Ce séjour de 5 jours à Saint-Tropez se pense entre Cheval Blanc Saint-Tropez et Lily of the Valley. Le rythme tient en 4 étapes. Deux journées posées près de Pampelonne, puis des séquences plus mobiles entre village, vignes et mer. C’est l’équilibre juste si vous voulez profiter sans courir. Comptez un budget indicatif de 12 000 à 18 000 EUR TTC pour deux, avec hôtel 5 étoiles, transferts privés, une journée bateau et quelques tables demandées. La meilleure fenêtre reste juin ou septembre, quand les routes tiennent encore. Au Cheval Blanc, palace distingué par Atout France, demandez les suites 301 à 303 côté port. La vue sur les yachts y reste plus dégagée que dans les étages inférieurs. Pour juillet-août, Club 55 se verrouille tôt. Les tables en front de plage partent souvent dans les 48 heures après l’ouverture des réservations, le 1er mars.',
  'This 5-day stay in Saint-Tropez works best between Cheval Blanc Saint-Tropez and Lily of the Valley. The pace is built around 4 stages. Two slower days near Pampelonne anchor the trip, with shorter moves between the port, hillside roads and time on the water. It gives you room to enjoy the peninsula without spending the week in transit. Plan roughly 12,000 to 18,000 EUR including tax for two, covering a 5-star hotel, private transfers, one boat day and sought-after lunch reservations. June and September are the easiest months for access and timing. At Cheval Blanc Saint-Tropez, a palace classified by Atout France, ask specifically for rooms 301 to 303 on the port side. Their line of sight stays clearer than lower floors. For Club 55, call when bookings open on 1 March if you travel in July or August. Front-row beach tables are usually gone within 48 hours.',
  'Quel est le meilleur itinéraire Saint-Tropez été en 5 jours ?',
  'Arrivée Cheval Blanc Saint-Tropez (port), Pampelonne plage Club 55 (2 nuits Lily of the Valley), journée citadelle et arrière-pays (Messardière), excursion bateau Porquerolles. Réserver Club 55 et restaurant Cheval Blanc 2-3 semaines avant en juillet-août. Éviter les week-ends 14 juillet et 15 août (saturation totale). Mis à jour mai 2026.',
  'What is the best 5-day itinerary for Saint-Tropez?',
  '5 days in Saint-Tropez for a luxe profile: Port de Saint-Tropez, Place des Lices, and Musée de l''Annonciade; then Pampelonne, Tahiti Beach, and Club 55; then the Citadelle, Chapelle Sainte-Anne, and Grimaud; finish with Calanques du Var by boat and Port Grimaud, with Porquerolles optional. Base at Hôtel Byblos. Best in July–September. Updated May 2026.',
  'FR',
  'Provence-Alpes-Côte d''Azur',
  'Saint-Tropez',
  array['luxe', 'mer']::text[],
  5::smallint,
  5::smallint,
  'luxe',
  'ete',
  '{}'::uuid[],
  '[{"step":1,"title_fr":"Jour 1 : Saint-Tropez — Port, village et marché des Lices","title_en":"Day 1: Saint-Tropez — Port, village and Les Lices market","body_fr":"Le premier jour se joue à pied, entre le port, les ruelles du village et la Place des Lices avant l’animation de fin de matinée.\n\nInstallez-vous au Cheval Blanc Saint-Tropez, palace distingué par Atout France, pour garder un accès direct à la mer et rejoindre le port en quelques minutes. Si votre arrivée est matinale, déposez les bagages puis partez vers la Place des Lices avant 10h le mardi ou le samedi, quand le marché reste fluide et que les étals sont encore bien tenus. Enchaînez avec le Musée de l’Annonciade, dans l’ancien port de pêche, puis remontez vers la Citadelle en fin de matinée. À 9h, la vue sur le golfe est plus nette et les remparts se visitent sans attente.\n\nRedescendez ensuite vers le quai Jean-Jaurès pour un apéritif au Café de Paris, en visant 18h30 pour capter le mouvement du port sans l’affluence du dîner. Le repère hôtelier est simple : demandez au concierge du Cheval Blanc une arrivée anticipée, puis une voiture pour la Citadelle en fin d’après-midi si la chaleur monte. Pour dîner, La Vague d’Or, table trois étoiles Michelin au sein du Cheval Blanc, se réserve plusieurs semaines en avance, avec préférence pour la première partie de service côté mer.\n\nMon conseil : au Cheval Blanc Saint-Tropez, demandez les suites 301 à 303, côté port. Au 3e étage, la vue sur les yachts reste dégagée, sans les palmiers des niveaux inférieurs.","body_en":"Day one works best on foot, moving between the port, the village lanes, and Place des Lices before late-morning activity builds. Check into Cheval Blanc Saint-Tropez, a palace distinguished by Atout France, so you keep direct access to the sea and can reach the port in minutes. If you arrive early, leave the luggage with the concierge and go straight to Place des Lices before 10:00 on Tuesday or Saturday. The market is still easy then, and the stalls are better kept. Continue to the Musée de l’Annonciade, set in the former fishing port, then head up to the Citadelle late in the morning. At 9:00, the view over the gulf is clearer, and the ramparts are quieter.\n\nAfter that, return to quai Jean-Jaurès for an aperitif at Café de Paris. Aim for 18:30. You catch the port in motion without the dinner rush. The hotel arrangement is simple. Ask the Cheval Blanc concierge for an early arrival, then a car to the Citadelle if the heat rises later in the day. For dinner, La Vague d’Or, the three-Michelin-star table inside Cheval Blanc, should be booked several weeks ahead. Ask for the first seating on the sea side.\n\nConcierge secret: at Cheval Blanc Saint-Tropez, request suites 301 to 303, port side. On the 3rd floor, the yacht view stays open, without the palms that block lower levels.","hotel_id":null,"duration_days":1,"city":"Saint-Tropez — Port & village","poi":["Port de Saint-Tropez","Place des Lices","Musée de l''Annonciade","Citadelle"]},{"step":2,"title_fr":"Jours 2-3 : Pampelonne — Plages privées et Club 55","title_en":"Days 2-3: Pampelonne — Private beaches and Club 55","body_fr":"À Pampelonne, tout se règle à l’heure près : départ tôt, plage avant le flux, déjeuner réservé, puis Ramatuelle au coucher du jour.\n\nBasez-vous à Lily of the Valley, hôtel 5 étoiles, membre Leading Hotels of the World, sur les hauteurs de La Croix-Valmer. Demandez la navette privée plage de 9h pour rejoindre Pampelonne avant l’afflux et choisir votre rythme entre Tahiti Beach et les secteurs plus calmes de la baie. Sur deux jours, gardez une matinée très simple : installation, baignade, retour léger à l’hôtel en début d’après-midi, puis seconde sortie plus tardive si vous souhaitez éviter le plein soleil.\n\nLe déjeuner au Club 55 demande une vraie discipline de réservation. En haute saison, confirmez au minimum deux semaines avant, et bien plus tôt pour juillet-août. Après la plage, montez à Ramatuelle village vers 19h30 pour un sunset plus calme que sur le littoral. Le repère hôtelier : faites organiser par le concierge de Lily of the Valley les transferts plage aller-retour, avec heure de reprise fixée dès le matin pour éviter l’attente au retour.\n\nPour la table, Club 55 reste la maison la plus demandée sur Pampelonne. Réservez le déjeuner pour 12h30, avant le pic de 13h30, et précisez si vous souhaitez être au plus près du sable. Mon conseil : appelez dès l’ouverture des réservations, le 1er mars, pour juillet-août. Les tables front de plage du secteur A partent en 48h.","body_en":"In Pampelonne, timing matters. Leave early, reach the beach before the flow, book lunch, then save Ramatuelle for sunset. Base yourself at Lily of the Valley, a 5-star hotel and member of Leading Hotels of the World, on the heights of La Croix-Valmer. Ask for the private beach shuttle at 9:00. It gets you to Pampelonne before the crowd and lets you choose your pace between Tahiti Beach and the quieter stretches of the bay. Over two days, keep the mornings simple. Settle in, swim, then return lightly to the hotel in the early afternoon. If you want a second outing, do it later to avoid the strongest sun.\n\nLunch at Club 55 needs real discipline. In high season, confirm at least two weeks ahead, and much earlier for July and August. After the beach, go up to Ramatuelle village around 19:30 for a calmer sunset than the coast offers. Ask the Lily of the Valley concierge to handle round-trip beach transfers, with the return time fixed in the morning so you do not wait.\n\nFor dining, Club 55 remains the most requested house on Pampelonne. Book lunch for 12:30, before the 13:30 peak, and specify if you want to be closest to the sand. Concierge secret: call as soon as reservations open on 1 March for July and August. Front-row tables in sector A are gone within 48 hours.","hotel_id":null,"duration_days":2,"city":"Pampelonne & Ramatuelle","poi":["Plage de Pampelonne","Tahiti Beach","Club 55","Ramatuelle village"]},{"step":3,"title_fr":"Jour 4 : Citadelle & arrière-pays — Vignes, chapelles et vue golfe","title_en":"Day 4: Citadelle & hinterland — Vineyards, chapels and gulf views","body_fr":"Le quatrième jour quitte le rivage dès l’ouverture, entre remparts, chapelles et route des vignes au-dessus du golfe de Saint-Tropez.\n\nCommencez par la Citadelle de Saint-Tropez à 9h. Vous profitez d’une lumière plus nette sur le golfe et d’un parcours encore vide autour des remparts. Enchaînez avec la Chapelle Sainte-Anne, liée à l’histoire locale et posée au-dessus de la ville, puis prenez la route vers Gassin par les vignes. Cette séquence fonctionne bien avant le déjeuner, car la circulation devient plus dense en fin de matinée sur les axes secondaires. Si vous souhaitez pousser jusqu’à Grimaud, gardez-le pour le début d’après-midi, quand le village retrouve un tempo plus régulier.\n\nLe repère hôtelier le plus cohérent ici est Château de la Messardière, palace distingué par Atout France, sur les hauteurs de Saint-Tropez. Demandez au concierge une voiture avec arrêts coordonnés Citadelle, Chapelle Sainte-Anne, puis route des vignes, afin d’éviter les recherches de stationnement. Pour déjeuner, la terrasse du Château de la Messardière reste le bon point de chute, avec vue mer et retour simple vers Saint-Tropez ou Grimaud selon votre programme.\n\nPour la table, réservez le déjeuner en terrasse pour 13h, en précisant une table dégagée côté golfe. Mon conseil : partez de la Citadelle dès l’ouverture, puis faites la Chapelle Sainte-Anne avant 10h30. Vous évitez à la fois le trafic montant et les groupes tardifs.","body_en":"Day four leaves the shoreline at opening time, between ramparts, chapels, and the vineyard road above the Golfe de Saint-Tropez. Start at the Citadelle de Saint-Tropez at 9:00. The light over the gulf is cleaner then, and the ramparts are still quiet. Continue to Chapelle Sainte-Anne, which sits above the town and is tied to local history, then take the road toward Gassin through the vineyards. This order works well before lunch, because traffic thickens on the secondary roads by late morning. If you want to continue to Grimaud, leave it for early afternoon, when the village settles into a steadier rhythm.\n\nThe most practical hotel base here is Château de la Messardière, a palace distinguished by Atout France, on the heights of Saint-Tropez. Ask the concierge for a car with coordinated stops at the Citadelle, Chapelle Sainte-Anne, then the vineyard road, so you avoid parking searches. For lunch, the terrace at Château de la Messardière is the right stop, with sea views and an easy return to Saint-Tropez or Grimaud depending on your plan.\n\nBook terrace lunch for 13:00, and ask for a clear table facing the gulf. Concierge secret: leave the Citadelle as soon as it opens, then do Chapelle Sainte-Anne before 10:30. You avoid both uphill traffic and later tour groups.","hotel_id":null,"duration_days":1,"city":"Saint-Tropez — Citadelle & arrière-pays","poi":["Citadelle de Saint-Tropez","Chapelle Sainte-Anne","Grimaud","Golfe de Saint-Tropez"]},{"step":4,"title_fr":"Jour 5 : Saint-Tropez — Excursion nautique et départ","title_en":"Day 5: Saint-Tropez — Boat excursion and departure","body_fr":"Le départ se pense depuis la mer, avec une sortie cadrée au quart d’heure pour profiter du large sans compromettre le retour au port.\n\nDepuis le Port de Saint-Tropez, faites organiser un semi-rigide ou un yacht privé avec départ entre 9h et 9h30. Deux formats fonctionnent bien. Le premier reste court et fluide, vers les calanques du Var, avec baignade et déjeuner à bord avant un retour vers 17h. Le second vise Porquerolles, à environ 1h30 de navigation selon la mer et le bateau. Dans ce cas, il faut confirmer la météo la veille au soir et limiter les escales pour garder une marge confortable avant le départ final.\n\nSi vous préférez une navigation plus douce, demandez un passage par Port Grimaud au retour, en fin d’après-midi, quand la lumière baisse et que le trafic nautique se calme. Le repère hôtelier le plus pratique est Cheval Blanc Saint-Tropez : faites gérer par le concierge la coordination bagages, check-out et transfert port, avec récupération des effets personnels dès 8h30. Cela évite de repasser par l’hôtel entre la mer et le départ.\n\nPour la table, le plus fiable reste un déjeuner à bord préparé à l’avance. Faites charger un panier salé la veille, avec heure de livraison confirmée au ponton. Mon conseil : exigez le nom du capitaine et le numéro du bateau la veille avant 20h. Au port, ce détail vous fait gagner vingt minutes au départ.","body_en":"For the final day, think from the sea first. Plan a tightly timed outing so you enjoy open water without risking the port return. From the Port de Saint-Tropez, arrange a semi-rigid or private yacht to depart between 9:00 and 9:30. Two formats work well. The first is short and efficient, toward the calanques du Var, with swimming and lunch on board before a return around 17:00. The second goes to Porquerolles, about 1 hour 30 minutes by boat depending on sea conditions and the vessel. If you choose that option, confirm the weather the night before and keep stops to a minimum so you retain a comfortable margin before departure.\n\nIf you prefer a gentler route, ask for a pass by Port Grimaud on the way back, late in the afternoon, when the light drops and nautical traffic eases. The most practical hotel base is Cheval Blanc Saint-Tropez. Have the concierge coordinate luggage, check-out, and transfer to the port, with personal belongings collected from 8:30. That avoids returning to the hotel between the sea and departure.\n\nFor lunch, the safest choice is a pre-arranged meal on board. Have a savory basket loaded the day before, with delivery time confirmed at the pontoon. Concierge secret: insist on the captain’s name and the boat number the night before, before 20:00. At the port, that detail saves you twenty minutes at departure.","hotel_id":null,"duration_days":1,"city":"Saint-Tropez — Excursion nautique & départ","poi":["Calanques du Var (bateau)","Port Grimaud","Les Porquerolles (option)"]}]'::jsonb,
  '[{"q_fr":"Quelle est la meilleure période pour visiter Saint-Tropez ?","a_fr":"La meilleure fenêtre va de mi-mai à fin juin, puis de début septembre à mi-octobre. La mer devient agréable dès juin, autour de 21 à 24 °C, et les routes restent praticables. Juillet-août concentre les yachts, mais aussi les embouteillages et les tarifs les plus hauts. Pour Pampelonne, réservez les plages privées 4 à 8 semaines avant. Pour Club 55 en juillet-août, appelez dès l’ouverture des réservations le 1er mars. Mis à jour mai 2026.","q_en":"When is the best time to visit Saint-Tropez?","a_en":"The sweet spot is mid-May to late June, then early September to mid-October. Sea temperatures are usually comfortable by June, around 21 to 24°C, and road access is still manageable. July and August bring the yacht scene, but also the worst traffic and the highest rates. For Pampelonne beach clubs, book 4 to 8 weeks ahead. For Club 55 in July and August, call as soon as reservations open on 1 March. Updated May 2026."},{"q_fr":"Comment arriver à Saint-Tropez sans voiture ?","a_fr":"Le plus simple passe par Nice ou Toulon. Depuis Nice Aéroport, comptez environ 2 h 30 à 3 h 30 avec train jusqu’à Saint-Raphaël puis bateau vert vers le port. Depuis Toulon, la navette maritime Les Bateaux Verts est plus directe en saison. En été, évitez les arrivées routières du samedi entre 11 h et 18 h. Si vous atterrissez en jet, l’aéroport de La Môle reste le plus proche, à environ 17 km.","q_en":"How do you get to Saint-Tropez without a car?","a_en":"The easiest route is via Nice or Toulon. From Nice Airport, allow roughly 2.5 to 3.5 hours using a train to Saint-Raphaël, then a Les Bateaux Verts ferry into the port. From Toulon, the seasonal ferry is more direct. In summer, avoid road transfers on Saturdays between 11 am and 6 pm, when traffic is at its worst. If you fly privately, La Môle airport is the closest, about 17 km away."},{"q_fr":"Quels sont les meilleurs hôtels luxe à Saint-Tropez ?","a_fr":"Pour le centre, Cheval Blanc Saint-Tropez, Palace au sens Atout France, reste le repère le plus fluide. Demandez les suites 301 à 303, au 3e étage côté port. La vue sur les yachts y est plus dégagée. Airelles Saint-Tropez, Château de la Messardière, Palace, convient mieux si vous voulez un grand domaine. Byblos Saint-Tropez, 5 étoiles, garde l’avantage social. Lily of the Valley, à La Croix-Valmer, fonctionne très bien pour mer et bien-être.","q_en":"Which luxury hotels are the best in Saint-Tropez?","a_en":"For staying in town, Cheval Blanc Saint-Tropez, officially a Palace under Atout France, is the sharpest choice. Ask for suites 301 to 303 on the third floor facing the port, where the yacht view is less obstructed. Airelles Saint-Tropez, Château de la Messardière, also Palace-rated, works better if you want a larger estate. Byblos Saint-Tropez, a five-star hotel, keeps a strong social edge. Lily of the Valley, in La Croix-Valmer, suits sea access and wellness."},{"q_fr":"Quel budget prévoir pour 5 jours à Saint-Tropez en été ?","a_fr":"Pour 5 jours en profil luxe, prévoyez 8 000 à 18 000 € TTC pour deux, hors shopping lourd et yacht à la journée. Comptez 1 200 à 3 500 € TTC par nuit dans un 5 étoiles ou Palace en haute saison. Un déjeuner de plage privée revient souvent à 120 à 250 € TTC par personne, rosé inclus. Avec transferts privés, soins et deux dîners étoilés Michelin, vous montez vite au-dessus de 20 000 € TTC.","q_en":"What budget should you plan for five summer days in Saint-Tropez?","a_en":"For a five-day luxury stay, plan on €8,000 to €18,000 total for two, including tax, excluding serious shopping and a full-day yacht charter. In peak summer, expect €1,200 to €3,500 per night including tax for a five-star hotel or Palace. A private beach lunch often lands between €120 and €250 per person with rosé. Add private transfers, spa treatments, and two Michelin-starred dinners, and the total can move past €20,000 including tax."},{"q_fr":"Comment réserver une table au Club 55 à Pampelonne ?","a_fr":"Pour juillet-août, appelez dès l’ouverture des réservations, le 1er mars. Les tables en front de plage, secteur A, partent souvent en 48 heures. Visez un déjeuner à 12 h 15 ou après 15 h, plus simple à obtenir que 13 h 30. Confirmez la veille par téléphone, pas seulement par e-mail. Si vous arrivez en annexe depuis un yacht, précisez-le au moment de la réservation. Mis à jour mai 2026.","q_en":"How do you book a table at Club 55 on Pampelonne Beach?","a_en":"For July and August, call as soon as reservations open on 1 March. Front-row beach tables in sector A are often gone within 48 hours. Aim for lunch at 12:15 pm or after 3 pm, which is usually easier to secure than 1:30 pm. Confirm again by phone the day before, not just by email. If you are arriving by tender from a yacht, mention it when you book. Updated May 2026."},{"q_fr":"Saint-Tropez est-il adapté pour un séjour en famille ?","a_fr":"Oui, si vous évitez le cœur de saison festive. Fin juin et début septembre fonctionnent mieux avec des enfants. Pampelonne a des eaux calmes le matin, surtout avant 11 h. Les hôtels avec vraie logistique famille sont plus pratiques hors centre, comme Château de la Messardière ou Lily of the Valley. En ville, les ruelles deviennent vite denses avec poussette. Pour dîner, réservez tôt, vers 19 h 30, service plus fluide et ambiance moins tendue.","q_en":"Is Saint-Tropez a good choice for a family holiday?","a_en":"Yes, provided you avoid the peak party stretch. Late June and early September work better with children. Pampelonne is usually calmest in the morning, especially before 11 am. Hotels with proper family logistics are easier outside the old center, such as Château de la Messardière or Lily of the Valley. In town, the lanes get crowded quickly with a stroller. For dinner, book early around 7:30 pm, when service is smoother and the mood quieter."},{"q_fr":"Quelles plages privées de Saint-Tropez valent le détour ?","a_fr":"À Pampelonne, Club 55 reste la référence historique pour le déjeuner. Bagatelle convient mieux si vous cherchez une ambiance plus sonore. Gigi Ramatuelle est bien réglé pour les groupes. Tropicana et Cabane Bambou gardent souvent un service plus simple à gérer en famille. Réservez les premiers rangs 2 à 6 semaines avant selon la période. Pour une arrivée plus calme, visez 10 h 30. Après 13 h, le parking et les accès se tendent nettement.","q_en":"Which private beaches in Saint-Tropez are actually worth your time?","a_en":"On Pampelonne, Club 55 remains the historic benchmark for lunch. Bagatelle suits a louder, more social mood. Gigi Ramatuelle is well run for groups. Tropicana and Cabane Bambou are often easier for families to manage. Book front-row sunbeds 2 to 6 weeks ahead depending on the month. For a smoother arrival, aim for 10:30 am. After 1 pm, parking and beach access become noticeably more complicated."},{"q_fr":"Peut-on louer un bateau à Saint-Tropez ?","a_fr":"Oui. Vous trouverez au port des day-boats, vedettes avec skipper et yachts plus importants. En été, comptez souvent 1 200 à 3 000 € TTC la journée pour un bateau à moteur avec skipper, hors carburant selon le contrat. Réservez 7 à 14 jours avant en juillet-août, davantage pour un modèle précis. Demandez un départ avant 10 h pour éviter le trafic nautique vers Pampelonne. Vérifiez aussi la place d’embarquement, souvent plus utile que la marque du bateau.","q_en":"Can you charter a boat in Saint-Tropez?","a_en":"Yes. The port offers day boats, skippered motor launches, and larger yachts. In summer, a motorboat with skipper often costs around €1,200 to €3,000 for the day including tax, with fuel sometimes billed separately depending on the contract. Book 7 to 14 days ahead in July and August, or earlier if you want a specific model. Ask for a departure before 10 am to avoid heavy marine traffic toward Pampelonne. Also confirm the exact boarding point."},{"q_fr":"Que faire à Saint-Tropez en dehors de la plage ?","a_fr":"Le vieux port se parcourt tôt, avant 9 h 30, quand les terrasses sont encore calmes. Montez ensuite à la Citadelle et au musée d’Histoire maritime pour le contexte local. L’Annonciade mérite aussi l’arrêt pour l’art du début du XXe siècle. Côté table, La Vague d’Or à Cheval Blanc compte 3 étoiles Michelin. Pour le marché de la place des Lices, visez mardi ou samedi avant 10 h. Après, la circulation devient pénible.","q_en":"What is there to do in Saint-Tropez besides the beach?","a_en":"Walk the old port early, before 9:30 am, when the café terraces are still quiet. Then head up to the Citadel and the Maritime History Museum for local context. The Musée de l’Annonciade is also worth your time for early 20th-century art. For dining, La Vague d’Or at Cheval Blanc holds 3 Michelin stars. If you want the market on Place des Lices, go on Tuesday or Saturday before 10 am. After that, traffic becomes tedious."},{"q_fr":"Saint-Tropez vs Ibiza — où passer ses vacances luxe en été ?","a_fr":"Choisissez Saint-Tropez si vous voulez une séquence courte, très réglée, entre port, Pampelonne et hôtels Palace. Tout se joue dans un rayon compact. Ibiza convient mieux à un séjour plus long, avec villas, criques et clubs dispersés. Côté mer, Saint-Tropez est plus simple en tender et en déjeuner de plage. Côté nuit, Ibiza offre davantage d’options. En août, Saint-Tropez demande des réservations plus serrées, souvent 6 à 10 semaines avant. Mis à jour mai 2026.","q_en":"Saint-Tropez or Ibiza: which is better for a luxury summer escape?","a_en":"Choose Saint-Tropez if you want a tightly edited short stay built around the port, Pampelonne, and Palace hotels. Everything happens within a compact radius. Ibiza works better for a longer trip, with villas, coves, and clubs spread across the island. For sea access, Saint-Tropez is easier for tenders and beach lunches. For nightlife, Ibiza offers more range. In August, Saint-Tropez usually requires tighter planning, often 6 to 10 weeks in advance. Updated May 2026."}]'::jsonb,
  '{}'::uuid[],
